-- ERBCustomizations: Table: ERBCustomizations
-- ----------------------------------------------------------------------------
INSERT INTO erb_customizations (erb_customization_id, name, title, sql_code, sql_target, customization_type)
VALUES ('calc-orders-item-count', 'calc_orders_item_count', '', '-- FunctionOverride: calc_orders_item_count
-- Errors in this file are non-fatal (runs without ON_ERROR_STOP).

CREATE OR REPLACE FUNCTION public.calc_orders_item_count(p_order_id text)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
BEGIN
  RETURN ((SELECT COUNT(*) FROM order_line_items WHERE "order" = p_order_id))::integer;
END;
$function$;
', 'Postgres', 'FunctionOverride') ON CONFLICT (erb_customization_id) DO NOTHING;

INSERT INTO erb_customizations (erb_customization_id, name, title, sql_code, sql_target, customization_type)
VALUES ('calc-orders-last-payment-date', 'calc_orders_last_payment_date', '', '-- FunctionOverride: calc_orders_last_payment_date
-- Errors in this file are non-fatal (runs without ON_ERROR_STOP).

CREATE OR REPLACE FUNCTION public.calc_orders_last_payment_date(p_order_id text)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
BEGIN
  RETURN (SELECT MAX(payment_date) FROM payments WHERE "order" = p_order_id);
END;
$function$;
', 'Postgres', 'FunctionOverride') ON CONFLICT (erb_customization_id) DO NOTHING;

INSERT INTO erb_customizations (erb_customization_id, name, title, sql_code, sql_target, customization_type)
VALUES ('calc-orders-payment-count', 'calc_orders_payment_count', '', '-- FunctionOverride: calc_orders_payment_count
-- Errors in this file are non-fatal (runs without ON_ERROR_STOP).

CREATE OR REPLACE FUNCTION public.calc_orders_payment_count(p_order_id text)
 RETURNS integer
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
BEGIN
  RETURN ((SELECT COUNT(*) FROM payments WHERE "order" = p_order_id))::integer;
END;
$function$;
', 'Postgres', 'FunctionOverride') ON CONFLICT (erb_customization_id) DO NOTHING;

